  CLASS
	NAME "Modelo MIHR - Escenario A1B"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME " "
    EXPRESSION ([pixel] = -9999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "Anomalía de pp (%)"
    EXPRESSION ([pixel] = -999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-10.9 - -8"
    EXPRESSION ([pixel] >= -10.9 AND [pixel] < -8)
    COLOR 243 255 20
  END
  CLASS
	NAME "-8 - -6"
    EXPRESSION ([pixel] >= -8 AND [pixel] < -6)
    COLOR 208 240 0
  END
  CLASS
	NAME "-6 - -4"
    EXPRESSION ([pixel] >= -6 AND [pixel] < -4)
    COLOR 0 255 0
  END
  CLASS
	NAME "-4 - -2"
    EXPRESSION ([pixel] >= -4 AND [pixel] < -2)
    COLOR 44 150 69
  END
  CLASS
	NAME "-2 - 0"
    EXPRESSION ([pixel] >= -2 AND [pixel] < 0)
    COLOR 80 196 51
  END
  CLASS
	NAME "0 - 1"
    EXPRESSION ([pixel] >= 0 AND [pixel] < 1)
    COLOR 25 230 168
  END
  CLASS
	NAME "1 - 2"
    EXPRESSION ([pixel] >= 1 AND [pixel] < 2)
    COLOR 0 168 132
  END
  CLASS
	NAME "2 - 3"
    EXPRESSION ([pixel] >= 2 AND [pixel] < 3)
    COLOR 41 248 255
  END
  CLASS
	NAME "3 - 4"
    EXPRESSION ([pixel] >= 3 AND [pixel] < 4)
    COLOR 0 166 255
  END
  CLASS
	NAME "4 - 5"
    EXPRESSION ([pixel] >= 4 AND [pixel] < 5)
    COLOR 0 0 255
  END
  CLASS
	NAME "5 - 6"
    EXPRESSION ([pixel] >= 5 AND [pixel] < 6)
    COLOR 168 0 230
  END
  CLASS
	NAME "6 - 7.7"
    EXPRESSION ([pixel] >= 6 AND [pixel] <= 7.7)
    COLOR 202 122 245
  END
END # Layer